// Some portions generated by Codex
package org.eclipse.rdf4j.query.trace;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.Map;

import org.junit.jupiter.api.Test;

import com.fasterxml.jackson.databind.ObjectMapper;

class QueryTraceJsonTest {

	private final ObjectMapper mapper = new ObjectMapper();

	@Test
	void roundTripDoesNotExposeSyntheticSuccessProperty() throws Exception {
		QueryTrace trace = QueryTrace.success(
				List.of(new QueryTrace.Pattern("sp-0", 0, "?s ?p ?o")),
				List.of(new QueryTrace.Frame(0, "probe", "sp-0", 0, Map.of(), Map.of(), Map.of())));

		String json = mapper.writeValueAsString(trace);
		QueryTrace roundTripped = mapper.readValue(json, QueryTrace.class);

		assertFalse(json.contains("\"success\""), json);
		assertTrue(roundTripped.isSuccess());
		assertNull(roundTripped.getError());
		assertEquals(1, roundTripped.getPatterns().size());
		assertEquals(1, roundTripped.getFrames().size());
	}

	@Test
	void deserializesLegacySuccessProperty() throws Exception {
		QueryTrace trace = mapper.readValue("{\"success\":true,\"patterns\":[],\"frames\":[]}", QueryTrace.class);

		assertTrue(trace.isSuccess());
		assertTrue(trace.getPatterns().isEmpty());
		assertTrue(trace.getFrames().isEmpty());
	}

	@Test
	void roundTripPreservesDistinctAndFilters() throws Exception {
		QueryTrace trace = mapper.readValue(
				"{\"distinct\":true,\"filters\":[\"FILTER(?a != ?c)\"],\"patterns\":[],\"frames\":[]}",
				QueryTrace.class);

		String json = mapper.writeValueAsString(trace);

		assertTrue(json.contains("\"distinct\":true"), json);
		assertTrue(json.contains("\"filters\":[\"FILTER(?a != ?c)\"]"), json);
	}
}
